CREATE POLICY "Clinic doctors manage clinic medicines" ON public.clinic_medicines FOR ALL TO authenticated USING (EXISTS (SELECT 1 FROM doctors WHERE doctors.id = auth.uid() AND doctors.clinic_id = clinic_medicines.clinic_id AND doctors.approved = true)) WITH CHECK (EXISTS (SELECT 1 FROM doctors WHERE doctors.id = auth.uid() AND doctors.clinic_id = clinic_medicines.clinic_id AND doctors.approved = true));